CREATE TABLE `planicaja` (
  `Id` int(11) NOT NULL AUTO_INCREMENT,
  `pl_fecha` date DEFAULT NULL,
  `pl_tipomov` varchar(50) NOT NULL DEFAULT '' COMMENT 'ventas-compras-pagos ctacte-gastos varios-ingresos varios-todo de un combo predefinido',
  `pl_detalle` varchar(200) NOT NULL DEFAULT '' COMMENT 'detalle del movimiento (desc articulo - desc pago -desc compra...)',
  `pl_cantidad` decimal(5,2) NOT NULL DEFAULT 0.00,
  `pl_ingresos` decimal(12,2) NOT NULL DEFAULT 0.00,
  `pl_egreso` decimal(12,2) NOT NULL DEFAULT 0.00,
  `pl_costo` decimal(12,2) NOT NULL DEFAULT 0.00,
  `pl_pagoscta` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'importe que ingresa a la planilla por algun pago a cuenta corriente',
  `pl_compras` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'Importe que egresa de planilla por compras de mercaderias u otras realizadas',
  `pl_cliente` varchar(50) NOT NULL DEFAULT '' COMMENT 'nombre del cliente que se atendio, no va siempre generalmente en los servicios se anota',
  `pl_tipopago` varchar(50) NOT NULL DEFAULT '' COMMENT 'viene de combo - Efectivo-Cheque-tarjeta-ctacte-transferencia-otros,,,,',
  `pl_detapago` varchar(200) NOT NULL DEFAULT '' COMMENT 'para explayarse, si hace falta en el pago - detalles como numeros de cheque etc.',
  `pl_garantia` varchar(200) NOT NULL DEFAULT '' COMMENT 'detalle de garantias sobre ventas o se<rvicios que quieran aclararse',
  `pl_observacion` varchar(250) NOT NULL DEFAULT '' COMMENT 'campo libre para poner lo que quieran',
  `pl_proved` varchar(30) NOT NULL DEFAULT '',
  `pl_ctacte` varchar(1) NOT NULL DEFAULT '' COMMENT 'estado del checkpoint de si es movimiento a cta cte',
  `pl_clavemov` int(7) NOT NULL DEFAULT 0,
  `pl_codcli` decimal(5,0) DEFAULT NULL,
  PRIMARY KEY (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=2826 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
